mapper.select:
SELECT e.id AS id, e.evaluator_name AS evaluatorName, e.evaluator_type AS evaluatorType, e.latest_version_id AS latestVersionId, COALESCE(v.version_no, 0) AS latestVersionNo, CASE WHEN COALESCE(v.version_no, 0) = 0 THEN '草稿' ELSE CONCAT('V', v.version_no) END AS latestVersionName, e.description AS description, e.created_date AS createdDate, e.last_updated_date AS lastUpdatedDate FROM t_eval_evaluator e LEFT JOIN t_eval_evaluator_version v ON e.latest_version_id = v.id AND v.space_id = #{spaceId} WHERE e.is_deleted = 0 AND e.space_id = #{spaceId}
AND e.evaluator_type = #{evaluatorType}
AND (#{like} = '%%' OR e.evaluator_name LIKE #{like}) ORDER BY e.last_updated_date DESC LIMIT #{size} OFFSET #{offset}
